INSERT INTO public.weapon_armament_spec (
  weapon_id,
  armament_name,
  description,
  physical_dimensions,
  construction_feedstock,
  usage_dependency,
  operation_principle,
  extended_spec,
  defects_and_risks,
  design_constraints
)
SELECT
  w.id,
  s.armament_name,
  s.description,
  s.physical_dimensions,
  s.construction_feedstock,
  s.usage_dependency,
  s.operation_principle,
  s.extended_spec,
  s.defects_and_risks,
  s.design_constraints
FROM seed s
JOIN public.weapons w ON w.sku_code = s.sku_code
ON CONFLICT (weapon_id) DO UPDATE
SET
  armament_name = EXCLUDED.armament_name,
  description = EXCLUDED.description,
  physical_dimensions = EXCLUDED.physical_dimensions,
  construction_feedstock = EXCLUDED.construction_feedstock,
