INSERT INTO public.weapon_merchandising (
  weapon_id,
  product_title,
  short_description,
  key_features,
  promo_copy,
  suggested_price_qc
)
SELECT
  w.id,
  s.product_title,
  s.short_description,
  s.key_features,
  s.promo_copy,
  s.suggested_price_qc
FROM seed s
JOIN public.weapons w ON w.sku_code = s.sku_code
ON CONFLICT (weapon_id) DO UPDATE
SET
  product_title = EXCLUDED.product_title,
  short_description = EXCLUDED.short_description,
  key_features = EXCLUDED.key_features,
  promo_copy = EXCLUDED.promo_copy,
  suggested_price_qc = EXCLUDED.suggested_price_qc,
  updated_at = now();

